svg.script:
    
        function createLine(x1, y1, x2, y2, color) {
            var svgns = "http://www.w3.org/2000/svg";
            var line = document.createElementNS(svgns, 'line');
            line.setAttribute('x1', x1);
            line.setAttribute('y1', y1);
            line.setAttribute('x2', x2);
            line.setAttribute('y2', y2);
            line.setAttribute('stroke', color);
            return line;
        }

        function drawLines() {
            var centerX = 500;
            var centerY = 500;
            var length = 499;
       var numberOfLines = 904;
      var rotationStep = 0.3982300884955752;
            var colors = ['#EE6666','#F4A15F', '#FAC758', '#A6CB6F', '#5470C6', '#EA7CCC', '#FC8452', '#3BA272', '#73C0DE'];
            for (var i = 0; i < numberOfLines; i++) {
                var angle = i * rotationStep * Math.PI / 180;
                var x2 = centerX + length * Math.sin(angle);
                var y2 = centerY - length * Math.cos(angle);
                var color = colors[i % colors.length];
                var line = createLine(centerX, centerY, x2, y2, color);
                document.documentElement.appendChild(line);
            }
        }

        window.onload = drawLines;
